import{_ as a,o,c as r,ag as t}from"./chunks/framework.BZohXCq9.js";const p=JSON.parse('{"title":"INFORMACIÓN","description":"","frontmatter":{},"headers":[],"relativePath":"maxgraves/funciones.md","filePath":"maxgraves/funciones.md"}'),c={name:"maxgraves/funciones.md"};function s(i,e,n,d,u,l){return o(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="informacion" tabindex="-1">INFORMACIÓN <a class="header-anchor" href="#informacion" aria-label="Permalink to &quot;INFORMACIÓN&quot;">​</a></h1><blockquote><p>MaxGraves es un plugin que permite crear tumbas en el servidor de Minecraft, para que los jugadores puedan recuperar sus objetos al morir.</p></blockquote><h2 id="_1-caracteristicas" tabindex="-1">1. Características <a class="header-anchor" href="#_1-caracteristicas" aria-label="Permalink to &quot;1. Características&quot;">​</a></h2><ul><li><p><code>Sistema de Tumbas:</code> Al morir, se genera una tumba donde se almacenan todos tus objetos y tu experiencia.</p></li><li><p><code>Recuperación Rápida:</code> Con un solo clic puedes recuperar todas tus pertenencias. La armadura y los objetos en la mano secundaria se equipan automáticamente.</p></li><li><p><code>Menú de Tumbas:</code> Al morir, puedes ejecutar el comando <code>/mg info</code> para ver un menú con todas tus tumbas activas.</p></li><li><p><code>Mapa de Teletransporte:</code> Al morir recibirás un mapa que, al hacer clic derecho, te teletransportará directamente a tu tumba. Este sistema está controlado por el permiso <code>maxgraves.tp</code>.</p></li><li><p><code>Acumulación de Tumbas:</code> Las tumbas se acumulan según la cantidad de muertes del jugador. La duración de cada tumba es configurable desde el archivo <code>config.yml</code>.</p></li></ul>',4)])])}const _=a(c,[["render",s]]);export{p as __pageData,_ as default};
